const items = $input.all();
return items.map(item => ({
  json: {
    ...item.json,
    image_prompt: `Educational ${item.json.post_type} illustration: ${item.json.title ?? item.json.chunk_text.slice(0, 200)}. Style: ${item.json.persona_slug === 'doodle-prof' ? 'rough hand-drawn doodle comic strip, 3 panels, black pen on white, stick figures with speech bubbles' : item.json.persona_slug === 'meme-lord' ? 'classic internet meme template with bold Impact font text overlay, funny and relatable' : item.json.persona_slug === 'exam-gremlin' ? 'exam paper aesthetic with bold red warning stamps and hand-drawn trap annotations, circled mistakes and angry scrawled corrections' : item.json.persona_slug === 'lecture-bestie' ? 'clean pastel infographic with friendly icons, lavender colour palette, clear section labels and simple diagrams' : item.json.persona_slug === 'study-bard' ? 'vibrant concert-poster style with musical notes and floating lyrics, sky blue and gold palette, bold decorative typography' : 'precise step-by-step mathematical diagram with numbered annotations, graph paper grid background, technical notation'}. No human faces. Square format.`
  }
}));

const items     = $input.all();
const buildData = $('Build image prompt').all();

const results = [];
for (let i = 0; i < items.length; i++) {
  const response  = items[i].json;
  const prevData  = buildData[i].json;
  const part      = response?.candidates?.[0]?.content?.parts?.[0];
  const b64       = part?.inlineData?.data ?? null;
  const mimeType  = part?.inlineData?.mimeType ?? 'image/png';

  if (!b64) continue;

  results.push({
    json: {
      ...prevData,
      image_b64: b64,
      mime_type: mimeType,
      file_path: `${prevData.material_id}/${prevData.persona_slug}-${prevData.chunk_index}-image.png`,
    },
    binary: {
      image_b64: { data: b64, mimeType: mimeType, fileName: `${prevData.persona_slug}-${prevData.chunk_index}-image.png` }
    }
  });
}
return results;

const uploadResponses = $input.all();
const extractData     = $('Extract image data').all();
const supabaseUrl     = $vars.SUPABASE_URL;

return uploadResponses.map((res, i) => {
  const prev     = extractData[i].json;
  const mediaUrl = `${supabaseUrl}/storage/v1/object/public/post-media/${prev.file_path}`;
  return {
    json: {
      material_id: prev.material_id,
      persona_id:  prev.persona_id,
      post_type:   prev.post_type,
      title:       prev.title ?? null,
      body:        prev.chunk_text.slice(0, 300),
      media_type:  'image',
      media_url:   mediaUrl,
      source:      'n8n',
      sort_order:  prev.chunk_index * 4 + 1,
    }
  };
});
